     9|
    10|import SwiftUI
    11|
    12|struct HomeView: View {
    13|    @State private var dealsModel = JVDealsViewModel()
    14|    @State private var homeFeedModel = HomeFeedViewModel()
    15|    @State private var liveMemberTotal: Int?
    16|    @State private var liveInvestorTotal: Int?
    17|    @State private var liveDealTotal: Int?
    18|    @State private var showProjectReels = false
    19|
    20|    var body: some View {
    21|        NavigationStack {
    22|            ScrollView {
    23|                VStack(alignment: .leading, spacing: 24) {
    24|                    header
    25|                    portfolioSnapshot
    26|                    quickInvestSection
    27|                    investorFirstFeedSection
    28|                    trustBadges
    29|                    footer
    30|                }
    31|                .padding(.vertical)
    32|            }
    33|            .background(Color.ivxBackground)
    34|            .refreshable {
    35|                await dealsModel.load()
    36|                await homeFeedModel.load()
    37|                await loadLiveStats()
    38|            }
    39|            .task {
    40|                await dealsModel.load()
    41|                await homeFeedModel.load()
    42|                await loadLiveStats()
    43|            }
    44|            .toolbar(.hidden, for: .navigationBar)
    45|            .fullScreenCover(isPresented: $showProjectReels) {
    46|                ProjectReelsView()
    47|            }
    48|        }
    49|    }
    50|
    51|    private var header: some View {
    52|        HStack(alignment: .center) {
    53|            VStack(alignment: .leading, spacing: 2) {
    54|                Text("IVXHOLDINGS")
    55|                    .font(.title2)
    56|                    .fontWeight(.heavy)
    57|                    .foregroundStyle(Color.ivxGold)
    58|                Text("Institutional Real Estate Investment")
    59|                    .font(.caption)
    60|                    .foregroundStyle(Color.ivxTextSecondary)
    61|            }
    62|            Spacer()
    63|            HStack(spacing: 10) {
    64|                Button {
    65|                    showProjectReels = true
    66|                } label: {
    67|                    Image(systemName: "film.stack")
    68|                        .font(.title3)
    69|                        .foregroundStyle(Color.ivxGold)
    70|                        .frame(width: 40, height: 40)
    71|                        .background(Color.ivxGold.opacity(0.15))
    72|                        .clipShape(Circle())
    73|                        .overlay(Circle().stroke(Color.ivxGold.opacity(0.3), lineWidth: 1))
    74|                }
    75|                .accessibilityLabel("Project Reels")
    76|                .accessibilityHint("Opens the dedicated Project Reels module — construction updates and drone footage")
    77|
    78|                Link(destination: URL(string: "https://ivxholding.com")!) {
    79|                    Image(systemName: "safari")
    80|                        .font(.title3)
    81|                        .foregroundStyle(Color.ivxGold)
    82|                        .frame(width: 40, height: 40)
    83|                        .background(Color.ivxCard)
    84|                        .clipShape(Circle())
    85|                }
    86|            }
    87|        }
    88|        .padding(.horizontal)
    89|    }
    90|
    91|    /// Mirrors Android PortfolioSnapshot — "Your Portfolio / All time".
    92|    private var portfolioSnapshot: some View {
    93|        VStack(alignment: .leading, spacing: 12) {
    94|            HStack {
    95|                Text("Your Portfolio")
    96|                    .font(.headline)
    97|                    .foregroundStyle(.white)
    98|                Spacer()
    99|                Text("All time")
   100|                    .font(.caption)
   101|                    .foregroundStyle(Color.ivxTextTertiary)
   102|            }
   103|            LazyVGrid(columns: [GridItem(.flexible()), GridItem(.flexible())], spacing: 12) {
   104|                StatCard(
   105|                    title: "Members",
   106|                    value: liveMemberTotal.map(String.init) ?? "—",
   107|                    icon: "person.3"
   108|                )
   109|                StatCard(
   110|                    title: "Investors",
   111|                    value: liveInvestorTotal.map(String.init) ?? "—",
   112|                    icon: "person.2"
   113|                )
   114|                StatCard(
   115|                    title: "Live Deals",
   116|                    value: liveDealTotal.map(String.init) ?? "—",
   117|                    icon: "building.2"
   118|                )
   119|                StatCard(title: "Annual Returns", value: "Up to 22%", icon: "arrow.up.right")
   120|            }
   121|        }
   122|        .padding(.horizontal)
   123|    }
   124|
   125|    /// Mirrors Android QuickInvestSection — "Explore Deals / All Options".
   126|    private var quickInvestSection: some View {
   127|        VStack(alignment: .leading, spacing: 12) {
   128|            IVXSectionHeader(
   129|                title: "Explore Deals",
   130|                actionTitle: "All Options",
   131|                actionURL: URL(string: "https://ivxholding.com/properties")
   132|            )
   133|            LazyVGrid(columns: [GridItem(.flexible()), GridItem(.flexible())], spacing: 12) {
   134|                QuickActionCard(
   135|                    icon: "house.and.flag",
   136|                    title: "Buy Property Shares",
   137|                    subtitle: "Fractional ownership in premium real estate",
   138|                    tint: .ivxGold,
   139|                    url: URL(string: "https://ivxholding.com/properties")!
   140|                )
   141|                QuickActionCard(
   142|                    icon: "person.2.badge.gearshape",
   143|                    title: "JV Partnerships",
   144|                    subtitle: "View JV Deals",
   145|                    tint: .ivxBlue,
   146|                    url: URL(string: "https://chat.ivxholding.com/investor")!
   147|                )
   148|                QuickActionCard(
   149|                    icon: "brain.head.profile",
   150|                    title: "Smart Investing",
   151|                    subtitle: "Get Started",
   152|                    tint: .ivxGreen,
   153|                    url: URL(string: "https://chat.ivxholding.com")!
   154|                )
   155|                QuickActionCard(
   156|                    icon: "chart.line.uptrend.xyaxis",
   157|                    title: "Investor Dashboard",
   158|                    subtitle: "Track performance & distributions",
   159|                    tint: .ivxOrange,
   160|                    url: URL(string: "https://chat.ivxholding.com/investor")!
   161|                )
   162|            }
   163|            .padding(.horizontal)
   164|        }
   165|    }
   166|
   167|    /// Investor-first feed — the CANONICAL block sequence from
   168|    /// /api/ivx/video-platform/home-feed (same order as landing + Android):
   169|    /// Featured Deal 1–3 → 1 Featured Project Video → Deal 4–6 → repeat.
   170|    private var investorFirstFeedSection: some View {
   171|        VStack(alignment: .leading, spacing: 12) {
   172|            IVXSectionHeader(
   173|                title: "Featured Deals",
   174|                actionTitle: "See All",
   175|                actionURL: URL(string: "https://ivxholding.com/#deals")
   176|            )
   177|            if homeFeedModel.isLoading && homeFeedModel.blocks.isEmpty {
   178|                HStack {
   179|                    ProgressView()
   180|                        .tint(.ivxGold)
   181|                    Text("Syncing live deals...")
   182|                        .font(.subheadline)
   183|                        .foregroundStyle(Color.ivxTextSecondary)
   184|                }
   185|                .frame(maxWidth: .infinity)
   186|                .padding(.vertical, 30)
   187|            } else if homeFeedModel.blocks.isEmpty {
   188|                fallbackDealsList
   189|            } else {
   190|                LazyVStack(spacing: 14) {
   191|                    ForEach(homeFeedModel.blocks) { block in
   192|                        if block.isVideo, let video = block.video {
   193|                            DealVideoCard(video: video)
   194|                        } else if block.isDeal, let deal = block.deal {
   195|                            HomeFeedDealCard(deal: deal)
   196|                        }
   197|                    }
   198|                }
   199|                .padding(.horizontal)
   200|            }
   201|        }
   202|    }
   203|
   204|    /// Offline fallback — local jv_deals list keeps the page alive if the
   205|    /// canonical home feed is unreachable.
   206|    @ViewBuilder
   207|    private var fallbackDealsList: some View {
   208|        if dealsModel.deals.isEmpty {
   209|            VStack(spacing: 6) {
   210|                Text("No deals available yet")
   211|                    .font(.subheadline)
   212|                    .fontWeight(.semibold)
   213|                    .foregroundStyle(.white)
   214|                Text("Check back soon for new opportunities")
   215|                    .font(.caption)
   216|                    .foregroundStyle(Color.ivxTextSecondary)
   217|            }
   218|            .frame(maxWidth: .infinity)
   219|            .padding(.vertical, 30)
   220|        } else {
   221|            LazyVStack(spacing: 14) {
   222|                ForEach(dealsModel.deals) { deal in
   223|                    JVDealCard(deal: deal)
   224|                }
   225|            }
   226|            .padding(.horizontal)
   227|        }
   228|    }
   229|
   230|    /// Mirrors Android InlineTrustBadges.
   231|    private var trustBadges: some View {
   232|        VStack(spacing: 8) {
   233|            TrustBadge(icon: "sparkles", title: "AI Investing", subtitle: "Smart analysis picks the best deals for you")
   234|            TrustBadge(icon: "lock.shield", title: "Secure Escrow", subtitle: "Escrow-protected funds on every investment")
   235|            TrustBadge(icon: "chart.bar.xaxis", title: "Beating Markets", subtitle: "Performance-focused real estate strategies")
   236|            TrustBadge(icon: "bolt.fill", title: "Instant Liquidity", subtitle: "Trade shares 24/7 — no lockup periods")
   237|        }
   238|        .padding(.horizontal)
   239|    }
   240|
   241|    private var footer: some View {
   242|        Text("IVX HOLDINGS LLC")
   243|            .font(.caption2)
   244|            .fontWeight(.semibold)
   245|            .foregroundStyle(Color.ivxTextTertiary)
   246|            .frame(maxWidth: .infinity)
   247|            .padding(.top, 8)
   248|    }
   249|
   250|    private func loadLiveStats() async {
   251|        do {
   252|            let counts = try await MembersRegistryService.fetchCounts()
   253|            liveMemberTotal = counts.members
   254|            liveInvestorTotal = counts.investors
   255|            liveDealTotal = counts.liveDeals
   256|        } catch {
   257|            print("[Home] Live stats fetch failed: \(error.localizedDescription)")
   258|        }
   259|    }
   260|}
